GeoDusterLists.PortMacro:
// PortMacro::GEMK1
// The lines below for hemisphere switching
// Hmag1[7:2] = GetKineticValue(Heading);
// Rval1[20:0] = RequestDelayedFormatted(20,Hmag1,#M1,%03.0f,0x0d0a,0x234d310d0a)
// The line below(commented) is for the request based mags
// Dm1[20:0] = RequestDelayed(10,0x234d310d0a)
// For parsing data from a GEM mag:
// $M1,50707.1061,0,1,0, 49,0037,001
// $M2,49554.8240,0,1,0, 49,0041,299
// 123456789012345678901234567890123
// the stream is 33 characters issued after the hardware clock and request with heading.
// Block the incoming data stream from $M1 for 29(35) characters
 Dm11[35:0] = ParseCount($M1,29,1)
// Perform the post of the data to the mux.
 Dm111[35:0] = Post(Dm11)

// PortMacro::GEMK2
// The lines below for hemisphere switching
// Hmag2[7:2] = GetKineticValue(Heading);
// Rval2[20:0] = RequestDelayedFormatted(20,Hmag2,#M2,%03.0f,0x0d0a,0x234d320d0a)
// The line below(commented) is for the request based mags
// Dm2[20:0] = RequestDelayed(10,0x234d320d0a)
// For parsing data from a GEM mag:
// $M1,50707.1061,0,1,0, 49,0037,001
// $M2,49554.8240,0,1,0, 49,0041,299
// 123456789012345678901234567890123
// the stream is 33 characters issued after the hardware clock and request with heading.
// Block the incoming data stream from $M2 for 29(35) characters
 Dm22[35:0] = ParseCount($M2,29,1)
// Perform the post of the data to the mux.
 Dm222[35:0] = Post(Dm22)

// PortMacro::XSENS
// Xsens device emits 140 characters after the clock

// Block the incoming data stream from the hex preamble for 140(145) characters
Dxsns[145:0] = ParseCount(0xFAFF3287,140,1)

// Perform the post of the data to the mux.
Dxsnsp[144:0] = Post(Dxsns)

// PortMacro::GDLas
// added 5 for sequence number lengths were 25(30)
////Dlr[30:0] = Request(0x234c30310d0a)
////Dld[30:0] = ParseCount($,25,1)
////Dldp[30:0] = Post(Dld)
//Dld[10:0] = ParseCount(0x0d0a,9,1)
Dld[14:0] = ParseFromTo($LAS,0x0d0a,1,0)
Dldp[14:0] = Post(Dld)

// PortMacro::GDGPS
// parses a zda string from the port
// Dzda1[34:0] = ParseFromTo($GPZDA,0x0d0a,1,0)
// parses a gga string from the port
Dgga1[86:0] = ParseFromTo($GPGGA,0x0d0a,1,0)
// Dgps[120:0] = Concat(Dzda1,Dgga1)
// Dgpsp[80:0] = Post(Dgps)
Dgpsp[80:0] = Post(Dgga1)

//PortMacro::GD485
D1r[8:0] = Request(0x2330310d)
///D1[8:0] = ParseCount(>,8,1)
D1[38:0] = ParseCount(>,36,1)
// D2r[8:0] = Request(0x2330320d)
////D2r[8:0] = RequestDelayed(10,0x2330320d)
////D2[8:0] = ParseCount(>,8,1)
// D3r[8:0] = Request(0x2330330d)
////D3r[8:0] = RequestDelayed(10,0x2330330d)
// added 5 for sequence number lengths were 24(62)
////D3[24:0] = ParseCount(>,24,1)
// added 5 for sequence number lengths were 40(80)
////D485[40:0] = Concat(D1,D2,D3)
////D485p[40:0] = Post(D485)
////D1p represented single channel ADC 7012F now 5ch
// D1p[10:0] = Post(D1)
 D1p[38:0] = Post(D1)

// PortMacro::GDRalt
// Block the incoming data stream from 0x10 0xDF 0x03 for 7 bytes
Dralt[8:0] = ParseCount(0x10DF03,7,1)
// Perform the post of the data to the mux
Draltp[8:0] = Post(Dralt)

//PortMacro::GDSpec
//Send request of #S01\r\n
Dspc55[8:0] = Request(0x235330310d0a)
// 584 bytes in the message but first one is skipped so parse 583
// doesnt seem to work for 583 - possibly a fault in simulator
// parse from 'SBC' for 582 bytes
Dspec[584:0] = ParseCount(SBC,583,1)
// perform the post
Dspecp[584:0] = Post(Dspec)

GeoDusterLists.MuxMacro:
// MuxMacro::Mux1
// get active waypoint and synch the clock
 Wayp[7:0] = GetActiveWaypoint(void)

 Dt2[25:0] = SynchClockToXsens(Dxsns,127,0xFAFF3287)

 Date[9:0]  = GetDate(void)
 Time[11:0] = GetTime(void)

 Xgps[15:8] = ExtractXsens1632(Dxsns,94,0xFAFF3287)
 Ygps[15:8] = ExtractXsens1632(Dxsns,88,0xFAFF3287)
 Zgps[7:1]  = ExtractXsens1632(Dxsns,100,0xFAFF3287)

 UTM[12:3] = ConvertToUtm(Xgps,Ygps)

 Quat[10:6] = ExtractXsensArray1632(Dxsns,64,4,0xFAFF3287)
 Roll[9:2]  = QuatToRoll(Quat)
 Pitch[9:2] = QuatToPitch(Quat)
 Yaw[9:2]   = QuatToYaw(Quat)

// Three parameters needed in V1.14 to establish Declination for position
 Hdg[9:2]   = QuatToHeading(Quat,Xgps,Ygps)

 CalData[12:8] = ExtractXsensArray1632(Dxsns,10,9,0xFAFF3287)
 VelData[10:6] = ExtractXsensArray1632(Dxsns,106,3,0xFAFF3287)

 Bin[258:0] = ToHex(Dxsns,0,128)

 Xst[4:0] = ExIEEEByteU(Dxsns,124)
 Xpr[4:0] = ExtractXsensParity(Dxsns,0xFAFF3287);

// Extract the hi byte
ByteH[4:0] = ExIEEEByteU(Dralt,3)
// Extract the lo byte
ByteL[4:0] = ExIEEEByteU(Dralt,4)
// Extract the status
ByteS[4:0] = ExIEEEByteU(Dralt,5)
// Calculate the altimeter
Raltr[8:2] = Evaluate({ByteH*255.0}+ByteL)
// Filter Steps in Raw Data to improve VLB
Ralt[8:2] = LowPass(Raltr,0.1,21)

// parse the laser
//// Lfil[8:1] = Extract(Dld,7,4)
//// Lspt[8:1] = Extract(Dld,14,4)
//// Lcnt[8:0] = Extract(Dld,21,4)
//// Lalt[8:1] = Evaluate({Lfil/10.0})
// Lalt[6:1]   = ExtractFromArray(Repl,5)
/// Lavg[8:1] = Evaluate({Lspt/10.0})
// Lalt[8:2] = Extract(Dld,2,6)
Lalt[8:2] = Extract(Dld,5,6)

// parse the mags
// Sensor Signal Amplitude
 A2[4:0] = Extract(Dm22,25,4)
 A1[4:0] = Extract(Dm11,25,4)
// Sensor Temperatures
 T2[3:0] = Extract(Dm22,21,3)
 T1[3:0] = Extract(Dm11,21,3)
// The following four lines line Extracts the Signal, Heater and HS bits:
 X1[3:0] = Extract(Dm11,15,1)
 Y1[3:0] = Extract(Dm11,17,1)
 Z1[3:0] = Extract(Dm11,19,1)
// The following Line concatenates the three bits into one word (I think?? JH):
// Mag1S[6:0] = Concat(Mag1x,Mag1y,Mag1z)
// The following four lines line Extracts the Signal, Heater and HS bits:
 X2[3:0] = Extract(Dm22,15,1)
 Y2[3:0] = Extract(Dm22,17,1)
 Z2[3:0] = Extract(Dm22,19,1)
// The following Line concatenates the three bits into one word (I think?? JH):
// Mag2S[6:0] = Concat(Mag2x,Mag2y,Mag2z)

 Mag1[12:4] = Extract(Dm11,4,10)
 Mag2[12:4] = Extract(Dm22,4,10)
 MagL[11:4] = Evaluate({Mag1-Mag2}/10.56)
// Tip to Tip on Pipistrel 10.56 Meters 
 Mag1D[9:4] = FourthDiff(Mag1)
 Mag2D[9:4] = FourthDiff(Mag2)

 // the following two line perform the post of the heading to the mags
 // they may be commented
 //Rval1[20:0] = PostVariableToPort_V0(COM5,Hdg,#M1,%03.0f,0x0d0a)
 //Rval2[20:0] = PostVariableToPort_V0(COM6,Hdg,#M2,%03.0f,0x0d0a)

//compensate the mags
 Cdata[15:8]  = Concat(Xgps,Ygps,Zgps,Quat,CalData,VelData)
 CmpRet[10:3] = CompensateParam(Cdata,Bin,0,3,Mag1,Mag2,MagL)
 Mag1C[12:4] = CompensateData(Mag1)
 Mag2C[12:4] = CompensateData(Mag2)
 MagLC[11:4] = CompensateData(MagL)

 // Extract VLF Values
 Vlf1[8:3] = Extract(D1,1,7)
 Vlf2[8:3] = Extract(D1,8,7)
 Vlf3[8:3] = Extract(D1,15,7)
 Vlf4[8:3] = Extract(D1,22,7)

 M1st[5:0] = GetMuxStatus(void)
 M1clk[12:0] = GetMuxInitTime(void)
  // Reminder Lalt has been removed between Zgps,...Lalt...,Ralt
  // M1txt[80:0] = OutTxt(MAG,3,Xpr,M1st,M1clk,Wayp,Date,Time,Xgps,Ygps,Zgps,Ralt,Mag1,A1,T1,X1,Y1,Z1,Mag2,A2,T2,X2,Y2,Z2,MagL,Mag1C,Mag2C,MagLC,Roll,Pitch,Yaw,Xst,Bin)
  // Add Ralt and VLF data Ch1,Ch2,Ch3,Ch4
  M1txt[80:0] = OutTxt(MAG,3,Xpr,M1st,M1clk,Wayp,Date,Time,Xgps,Ygps,Zgps,Lalt,Raltr,Ralt,Mag1,A1,T1,X1,Y1,Z1,Mag1D,Mag2,A2,T2,X2,Y2,Z2,Mag2D,MagL,Mag1C,Mag2C,MagLC,Vlf1,Vlf2,Vlf3,Vlf4,Roll,Pitch,Yaw,Xst,Bin)

//MuxMacro::Mux3
// PROBLEM with Sync
// // // Dt3[25:0]  = SynchClockToGPZDA(Dgps)
 dWayp[9:0]  = GetActiveWaypoint(void)
// mTime[11:0] = GetTime(void)

// Extract the Diff GPS data Lat Lon
 Xdgps[16:9] = ExtractDelimGGA(Dgga1,$GPGGA,0x2c,4);
 Ydgps[16:9] = ExtractDelimGGA(Dgga1,$GPGGA,0x2c,2);
 Zdgps[9:3]  = ExtractDelim(Dgga1,$GPGGA,0x2c,8);
 dTime[10:2] = ExtractDelim(Dgga1,$GPGGA,0x2c,0);
 dSNo[5:0]   = ExtractDelim(Dgga1,$GPGGA,0x2c,6);
 dHdop[6:1]  = ExtractDelim(Dgga1,$GPGGA,0x2c,7);
 dDOn[5:0]   = ExtractDelim(Dgga1,$GPGGA,0x2c,5);
 dAge[5:1]   = ExtractDelim(Dgga1,$GPGGA,0x2c,12);
 dSID[5:0]   = ExtractDelim(Dgga1,$GPGGA,0x2c,13);

 M3st[5:0] = GetMuxStatus(void)
 M3clk[12:0] = GetMuxInitTime(void)

 M3txt[80:0] = OutTxt(GGA,3,M3st,M3clk,dWayp,dTime,Xdgps,Ydgps,Zdgps,dSNo,dHdop,dDOn,dAge,dSID)
